const PORT_CTRL_SELECT: usize = 10;
const PORT_CTRL_NOTE: usize = 11;
const PORT_CTRL_CHORD: usize = 12;
const PORT_CTRL_FGAIN: usize = 13;
const PORT_CTRL_FQ: usize = 14;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_PITCH.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            bool_parameter("bypass", "Bypass", None, Some(false)),
            float_parameter("wetdry", "Wet/Dry", None, Some(64.0), 0.0, 127.0, 1.0, ParameterUnit::None),
            float_parameter("pan", "Pan", None, Some(0.0), -64.0, 63.0, 1.0, ParameterUnit::None),
            float_parameter("gain", "Gain", None, Some(0.0), -64.0, 63.0, 1.0, ParameterUnit::None),
            float_parameter("int", "Interval", None, Some(0.0), -12.0, 12.0, 0.1, ParameterUnit::None),
            float_parameter("freq", "Filter Frequency", None, Some(6000.0), 20.0, 26000.0, 10.0, ParameterUnit::Hertz),
            bool_parameter("select", "Select Chord Mode", None, Some(false)),
            float_parameter("note", "Note", None, Some(0.0), 0.0, 23.0, 0.1, ParameterUnit::None),
            float_parameter("chord", "Chord", None, Some(0.0), 0.0, 33.0, 0.1, ParameterUnit::None),
            float_parameter("fgain", "Filter Gain", None, Some(0.0), -64.0, 63.0, 1.0, ParameterUnit::None),
            float_parameter("fq", "Filter Q", None, Some(0.0), -64.0, 63.0, 1.0, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let wetdry = required_f32(params, "wetdry").map_err(anyhow::Error::msg)?;
    let pan = required_f32(params, "pan").map_err(anyhow::Error::msg)?;
    let gain = required_f32(params, "gain").map_err(anyhow::Error::msg)?;
    let int = required_f32(params, "int").map_err(anyhow::Error::msg)?;
    let freq = required_f32(params, "freq").map_err(anyhow::Error::msg)?;
    let select = required_bool(params, "select").map_err(anyhow::Error::msg)?;
    let note = required_f32(params, "note").map_err(anyhow::Error::msg)?;
    let chord = required_f32(params, "chord").map_err(anyhow::Error::msg)?;
    let fgain = required_f32(params, "fgain").map_err(anyhow::Error::msg)?;
    let fq = required_f32(params, "fq").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_WETDRY, wetdry),
        (PORT_CTRL_PAN, pan),
        (PORT_CTRL_GAIN, gain),
        (PORT_CTRL_INT, int),
        (PORT_CTRL_FREQ, freq),
        (PORT_CTRL_SELECT, if select { 1.0 } else { 0.0 }),
        (PORT_CTRL_NOTE, note),
        (PORT_CTRL_CHORD, chord),
        (PORT_CTRL_FGAIN, fgain),
        (PORT_CTRL_FQ, fq),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT_L, PORT_AUDIO_IN_INPUT_R], &[PORT_AUDIO_OUT_OUTPUT_L, PORT_AUDIO_OUT_OUTPUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

pub const MODEL_DEFINITION: PitchModelDefinition = PitchModelDefinition {
    id: MODEL_ID, display_name: DISPLAY_NAME, brand: BRAND,
    backend_kind: PitchBackendKind::Lv2, schema, build,
    supported_instruments: block_core::ALL_INSTRUMENTS, knob_layout: &[],
};
